import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Assume that the name should be stored in a fixed-size buffer
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Copy the user input into the fixed-size buffer with bounds checking
        int length = Math.min(name.length(), bufferSize);
        for (int i = 0; i < length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Your name is: " + new String(buffer, 0, length));
    }
}

